#include <stdio.h>
#include <stdlib.h>
#define MAXN 200005
int T, N;
int parent[MAXN];
int find(int x) {
    if (parent[x] != x) parent[x] = find(parent[x]);
    return parent[x];
}
int unionSet(int x, int y) {
    int rootx = find(x);
    int rooty = find(y);
    if (rootx != rooty) {
        parent[rootx] = rooty;
        return 1;
    }
    return 0;
}
int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int edges1[N-1][2], edges2[N-1][2];
        for (int i = 0; i < N-1; i++) {
            scanf("%d %d", &edges1[i][0], &edges1[i][1]);
        }
        for (int i = 0; i < N-1; i++) {
            scanf("%d %d", &edges2[i][0], &edges2[i][1]);
        }
        for (int i = 0; i < N-1; i++) {
            int count = 0;
            for (int j = 0; j < N-1; j++) {
                for (int k = 1; k <= N; k++) parent[k] = k;
                for (int k = 0; k < N-1; k++) {
                    if (k != i) unionSet(edges1[k][0], edges1[k][1]);
                }
                unionSet(edges2[j][0], edges2[j][1]);
                int components = 0;
                for (int k = 1; k <= N; k++) {
                    if (parent[k] == k) components++;
                }
                if (components == 1) {
                    for (int k = 1; k <= N; k++) parent[k] = k;
                    for (int k = 0; k < N-1; k++) {
                        if (k != j) unionSet(edges2[k][0], edges2[k][1]);
                    }
                    unionSet(edges1[i][0], edges1[i][1]);
                    int components2 = 0;
                    for (int k = 1; k <= N; k++) {
                        if (parent[k] == k) components2++;
                    }
                    if (components2 == 1) count++;
                }
            }
            printf("%d", count);
            if (i < N-2) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

